     projectPath,
     onChange: useCallback(() => {
       const now = Date.now();
       if (now - lastFetchRef.current > 1000) {
         lastFetchRef.current = now;
         fetchData();
       }
     }, [fetchData]),
     enabled: !!projectPath,
   });
   ```

