import { useState, useCallback, useEffect } from 'react';
import {
  Button,
  Card,
  CardBody,
  CardTitle,
  Content,
  Label,
  Masthead,
  MastheadBrand,
  MastheadMain,
  Page,
  PageSection,
  Title,
  Alert,
  AlertActionCloseButton,
} from '@patternfly/react-core';
import { FolderOpenIcon, CogIcon } from '@patternfly/react-icons';
import { TabBar, KanbanBoard, LogPanel, TerminalPanel, ProjectSelector, ProgressCard, Settings } from './components';
import type { HQSettings } from './components';
import type { LogEntry } from './components';
import type { Project, Feature } from './state/store';
import { listen } from '@tauri-apps/api/event';

// Mock projects for demonstration
const createMockProject = (id: string, name: string): Project => ({
  id,
  path: `/Users/example/${name.toLowerCase().replace(/\s+/g, '-')}`,
  name,
  harness: {
