    43→}
    44→
    45→// ============================================================================
    46→// SLICES
    47→// ============================================================================
    48→
    49→const uiSlice = createSlice({
    50→  id: 'ui',
    51→  cache: { policy: 'session' },
    52→  initial: {
    53→    activeTab: '' as string,
    54→    theme: 'system' as 'light' | 'dark' | 'system',
    55→    projectOrder: [] as string[],
    56→    sidebarCollapsed: false,
