    58→  },
    59→  reducers: {
    60→    setActiveTab: (state, tabId: string) => {
    61→      state.activeTab = tabId;
    62→    },
    63→    setTheme: (state, theme: 'light' | 'dark' | 'system') => {
    64→      state.theme = theme;
    65→    },
    66→    addProject: (state, projectId: string) => {
    67→      if (!state.projectOrder.includes(projectId)) {
    68→        state.projectOrder.push(projectId);
    69→      }
    70→      state.activeTab = projectId;
    71→    },
    72→    removeProject: (state, projectId: string) => {
    73→      const idx = state.projectOrder.indexOf(projectId);
    74→      state.projectOrder = state.projectOrder.filter((id) => id !== projectId);
    75→      if (state.activeTab === projectId) {
    76→        state.activeTab = state.projectOrder[Math.max(0, idx - 1)] || '';
    77→      }
    78→    },
    79→    reorderProjects: (state, order: string[]) => {
    80→      state.projectOrder = order;
    81→    },
    82→    toggleSidebar: (state) => {
    83→      state.sidebarCollapsed = !state.sidebarCollapsed;
    84→    },
    85→    setLogPanelHeight: (state, height: number) => {
    86→      state.logPanelHeight = height;
    87→    },
    88→  },
    89→});
    90→
    91→const projectsSlice = createSlice({
    92→  id: 'projects',
    93→  cache: { policy: 'private' },
    94→  initial: {} as Record<string, Project>,
    95→  reducers: {
    96→    set: (state, project: Project) => {
    97→      state[project.id] = project;
    98→    },
    99→    remove: (state, projectId: string) => {
   100→      delete state[projectId];
   101→    },
   102→  },
   103→});
   104→
   105→const processesSlice = createSlice({
   106→  id: 'processes',
   107→  cache: { policy: 'session' },
   108→  initial: {} as Record<string, Process>,
   109→  reducers: {
   110→    spawn: (state, process: Process) => {
   111→      state[process.id] = process;
   112→    },
   113→    updateStatus: (state, payload: { id: string; status: 'running' | 'stopped' | 'error' }) => {
   114→      if (state[payload.id]) {
   115→        state[payload.id].status = payload.status;
   116→      }
   117→    },
   118→    kill: (state, processId: string) => {
   119→      delete state[processId];
   120→    },
   121→  },
   122→});
   123→
   124→const MAX_LOGS_PER_PROCESS = 10000;
   125→
   126→const logsSlice = createSlice({
   127→  id: 'logs',
   128→  cache: { policy: 'session' },
   129→  initial: {
   130→    entries: {} as Record<string, LogEntry[]>,
   131→    autoScroll: true,
   132→    filter: '' as string,
   133→  },
   134→  reducers: {
   135→    append: (state, entry: LogEntry) => {
   136→      if (!state.entries[entry.processId]) {
   137→        state.entries[entry.processId] = [];
   138→      }
   139→      state.entries[entry.processId].push(entry);
   140→      if (state.entries[entry.processId].length > MAX_LOGS_PER_PROCESS) {
   141→        state.entries[entry.processId] = state.entries[entry.processId].slice(-MAX_LOGS_PER_PROCESS);
   142→      }
   143→    },
   144→    clear: (state, processId: string) => {
   145→      state.entries[processId] = [];
   146→    },
   147→    clearAll: (state) => {
   148→      state.entries = {};
   149→    },
   150→    setAutoScroll: (state, autoScroll: boolean) => {
   151→      state.autoScroll = autoScroll;
   152→    },
   153→    setFilter: (state, filter: string) => {
   154→      state.filter = filter;
   155→    },
   156→  },
   157→});
   158→
   159→const featuresSlice = createSlice({
   160→  id: 'features',
   161→  cache: { policy: 'private' },
   162→  initial: {
   163→    items: [] as Feature[],
   164→    loading: false,
   165→    error: null as string | null,
   166→  },
   167→  reducers: {
   168→    setFeatures: (state, features: Feature[]) => {
   169→      state.items = features;
   170→      state.loading = false;
   171→      state.error = null;
   172→    },
   173→    setLoading: (state, loading: boolean) => {
   174→      state.loading = loading;
   175→    },
   176→    setError: (state, error: string) => {
