   186→
   187→export const appMachine = createMachine({
   188→  id: 'hq',
   189→  slices: {
   190→    ui: uiSlice,
   191→    projects: projectsSlice,
   192→    processes: processesSlice,
   193→    logs: logsSlice,
   194→    features: featuresSlice,
   195→  },
   196→});
   197→
   198→// ============================================================================
   199→// SELECTORS (type-safe functions)
   200→// ============================================================================
   201→
   202→// eslint-disable-next-line @typescript-eslint/no-explicit-any
   203→type MachineState = any;
   204→
   205→export const selectors = {
   206→  activeProject: (state: MachineState): Project | null => {
   207→    const activeTab = state.ui?.activeTab;
   208→    return activeTab ? state.projects?.[activeTab] : null;
