import { createMachine, createSlice } from '@zazcart/tools';

// ============================================================================
// TYPES
// ============================================================================

export interface Project {
  id: string;
  path: string;
  name: string;
  harness: {
    progressFile: string;
    featuresFile: string;
  };
}

export interface Feature {
  id: string;
  description: string;
  category: string;
  priority: string;
  status: string;
  passes: boolean;
  steps: string[];
}

export interface Process {
  id: string;
  projectId: string;
  command: string;
  status: 'running' | 'stopped' | 'error';
  pid?: number;
}

export interface LogEntry {
  id: string;
  processId: string;
  timestamp: number;
  content: string;
  level: 'info' | 'warn' | 'error' | 'debug';
}

// ============================================================================
// STATE TYPES (for proper slice inference)
// ============================================================================

interface UIState {
  activeTab: string;
  theme: 'light' | 'dark' | 'system';
  projectOrder: string[];
  sidebarCollapsed: boolean;
  logPanelHeight: number;
}

type ProjectsState = Record<string, Project>;
type ProcessesState = Record<string, Process>;

interface LogsState {
  entries: Record<string, LogEntry[]>;
  autoScroll: boolean;
  filter: string;
}

interface FeaturesState {
  items: Feature[];
  loading: boolean;
  error: string | null;
}

// ============================================================================
// SLICES
// ============================================================================

const uiSlice = createSlice({
  id: 'ui',
  cache: { policy: 'session' },
  initial: {
    activeTab: '',
    theme: 'system',
    projectOrder: [],
    sidebarCollapsed: false,
    logPanelHeight: 200,
  } as UIState,
  reducers: {
    setActiveTab: (state, tabId: string) => {
      state.activeTab = tabId;
    },
    setTheme: (state, theme: 'light' | 'dark' | 'system') => {
      state.theme = theme;
    },
    addProject: (state, projectId: string) => {
      if (!state.projectOrder.includes(projectId)) {
        state.projectOrder.push(projectId);
      }
      state.activeTab = projectId;
    },
    removeProject: (state, projectId: string) => {
      const idx = state.projectOrder.indexOf(projectId);
      state.projectOrder = state.projectOrder.filter((id) => id !== projectId);
      if (state.activeTab === projectId) {
        state.activeTab = state.projectOrder[Math.max(0, idx - 1)] || '';
      }
    },
    reorderProjects: (state, order: string[]) => {
      state.projectOrder = order;
    },
    toggleSidebar: (state) => {
      state.sidebarCollapsed = !state.sidebarCollapsed;
    },
    setLogPanelHeight: (state, height: number) => {
      state.logPanelHeight = height;
    },
  },
});

// Use helper to create typed initial state for Record types
const createProjectsInitial = (): ProjectsState => ({});

const projectsSlice = createSlice({
  id: 'projects',
  cache: { policy: 'private' },
  initial: createProjectsInitial(),
  reducers: {
    set: (state, project: Project) => {
      (state as ProjectsState)[project.id] = project;
    },
    remove: (state, projectId: string) => {
      delete (state as ProjectsState)[projectId];
    },
  },
});

const createProcessesInitial = (): ProcessesState => ({});

const processesSlice = createSlice({
  id: 'processes',
  cache: { policy: 'session' },
  initial: createProcessesInitial(),
  reducers: {
    spawn: (state, process: Process) => {
      (state as ProcessesState)[process.id] = process;
    },
    updateStatus: (state, payload: { id: string; status: 'running' | 'stopped' | 'error' }) => {
      const typedState = state as ProcessesState;
      if (typedState[payload.id]) {
        typedState[payload.id].status = payload.status;
      }
    },
    kill: (state, processId: string) => {
      delete (state as ProcessesState)[processId];
    },
  },
});

const MAX_LOGS_PER_PROCESS = 10000;

const logsSlice = createSlice({
  id: 'logs',
  cache: { policy: 'session' },
  initial: {
    entries: {},
    autoScroll: true,
    filter: '',
  } as LogsState,
  reducers: {
    append: (state, entry: LogEntry) => {
      const typedState = state as LogsState;
      if (!typedState.entries[entry.processId]) {
        typedState.entries[entry.processId] = [];
      }
      typedState.entries[entry.processId].push(entry);
      if (typedState.entries[entry.processId].length > MAX_LOGS_PER_PROCESS) {
        typedState.entries[entry.processId] = typedState.entries[entry.processId].slice(-MAX_LOGS_PER_PROCESS);
      }
    },
    clear: (state, processId: string) => {
      (state as LogsState).entries[processId] = [];
    },
    clearAll: (state) => {
      (state as LogsState).entries = {};
    },
    setAutoScroll: (state, autoScroll: boolean) => {
      state.autoScroll = autoScroll;
    },
    setFilter: (state, filter: string) => {
      state.filter = filter;
    },
  },
});

const featuresSlice = createSlice({
  id: 'features',
  cache: { policy: 'private' },
  initial: {
    items: [],
    loading: false,
    error: null,
  } as FeaturesState,
  reducers: {
    setFeatures: (state, features: Feature[]) => {
      const typedState = state as FeaturesState;
      typedState.items = features;
      typedState.loading = false;
      typedState.error = null;
    },
    setLoading: (state, loading: boolean) => {
      state.loading = loading;
    },
    setError: (state, error: string) => {
      state.error = error;
      state.loading = false;
    },
  },
});

// ============================================================================
// APP MACHINE
// ============================================================================

export const appMachine = createMachine({
  id: 'hq',
  slices: {
    ui: uiSlice,
    projects: projectsSlice,
    processes: processesSlice,
    logs: logsSlice,
    features: featuresSlice,
  },
});

// ============================================================================
// SELECTORS (type-safe functions)
// ============================================================================

export const selectors = {
  activeProject: (state: AppState): Project | null => {
    const activeTab = state.ui?.activeTab;
    return activeTab ? state.projects?.[activeTab] : null;
  },

  projectsArray: (state: AppState): Project[] => {
    const projectOrder = state.ui?.projectOrder || [];
    return projectOrder.map((id: string) => state.projects?.[id]).filter(Boolean) as Project[];
  },

  activeProcesses: (state: AppState): Process[] => {
    const activeTab = state.ui?.activeTab;
    const processes = state.processes || {};
    return Object.values(processes).filter((p) => p.projectId === activeTab);
  },

  logsForProcess: (state: AppState, processId: string): LogEntry[] => {
    const logs = state.logs?.entries?.[processId] || [];
    const filter = (state.logs?.filter || '').toLowerCase();
    if (!filter) return logs;
    return logs.filter((log) => log.content.toLowerCase().includes(filter));
  },

  featureStats: (state: AppState) => {
    const features: Feature[] = state.features?.items || [];
    const total = features.length;
    const completed = features.filter((f) => f.passes).length;
    return { total, completed, remaining: total - completed };
  },
};

// ============================================================================
// EXPORTS
// ============================================================================

export interface AppState {
  ui: UIState;
  projects: ProjectsState;
  processes: ProcessesState;
  logs: LogsState;
  features: FeaturesState;
}

