## State Management (using @zazcart/tools)

### Schema Validation

```typescript
import { createModel, InferType } from '@zazcart/tools';

// Project Schema - using string-based type definitions
const ProjectSchema = createModel({
  id: 'string',
  path: 'string',
  name: 'string',
  harness: {
    properties: {
      progressFile: 'string',
      featuresFile: 'string',
    },
  },
});

type Project = InferType<typeof ProjectSchema>;

// Feature Schema (from harness)
const FeatureSchema = createModel({
  id: 'string',
  description: 'string',
  category: 'string',
  passes: 'boolean',
  steps: 'string[]',
});

type Feature = InferType<typeof FeatureSchema>;

// Process Schema
const ProcessSchema = createModel({
  id: 'string',
  projectId: 'string',
  command: 'string',
  status: { enum: ['running', 'stopped', 'error'] },
  pid: 'number?', // optional
});

type Process = InferType<typeof ProcessSchema>;

// Validation usage
const project = ProjectSchema.parse(rawData);     // throws on invalid
const isValid = ProjectSchema.isValid(rawData);   // returns boolean
```

### State Machine

```typescript
import { createMachine, createSlice, createAsyncSlice } from '@zazcart/tools';
import { invoke } from '@tauri-apps/api/core';

// UI Slice - synchronous state with reducers
const uiSlice = createSlice({
  id: 'ui',
  cache: { policy: 'session' },
  initial: {
    activeTab: '',
    theme: 'system' as 'light' | 'dark' | 'system',
    projectOrder: [] as string[],
  },
  reducers: {
    setActiveTab: (state, tabId: string) => {
      state.activeTab = tabId;
    },
    setTheme: (state, theme: 'light' | 'dark' | 'system') => {
      state.theme = theme;
    },
    addProject: (state, projectId: string) => {
      state.projectOrder.push(projectId);
    },
    removeProject: (state, projectId: string) => {
      state.projectOrder = state.projectOrder.filter((id) => id !== projectId);
    },
    reorderProjects: (state, order: string[]) => {
      state.projectOrder = order;
    },
  },
});

// Projects Slice - synchronous state for project data
const projectsSlice = createSlice({
  id: 'projects',
  cache: { policy: 'private' },
  initial: {} as Record<string, Project>,
  reducers: {
    set: (state, project: Project) => {
      state[project.id] = project;
    },
    remove: (state, projectId: string) => {
      delete state[projectId];
    },
  },
});

// Processes Slice - for PTY process tracking
const processesSlice = createSlice({
  id: 'processes',
  cache: { policy: 'session' },
  initial: {} as Record<string, Process>,
  reducers: {
    spawn: (state, process: Process) => {
      state[process.id] = process;
    },
    updateStatus: (state, payload: { id: string; status: Process['status'] }) => {
      if (state[payload.id]) {
        state[payload.id].status = payload.status;
      }
    },
    kill: (state, processId: string) => {
      delete state[processId];
    },
  },
});

// Features Slice - async slice for fetching harness features
const featuresSlice = createAsyncSlice({
  id: 'features',
  cache: { policy: 'private' },
  context: {},
  // The load function fetches data - called when actions.load() is dispatched
  async load(projectPath: string) {
    const response = await invoke('harness:read_features', { path: projectPath });
    return response as Feature[];
  },
});

// Async slice state shape:
// {
//   loading: boolean,   // true while load() is running
//   loaded: boolean,    // true after successful load
//   failed: boolean,    // true if load() threw
//   error: string|null, // error message if failed
//   value: T|null,      // the loaded data
//   changes: number,    // increment counter
// }

// Async slice auto-generated actions:
// - actions.load(payload)  → triggers load function, sets loading=true
// - actions.success(data)  → sets value, loaded=true
// - actions.fail({ error }) → sets error, failed=true
// - actions.clear()        → resets to initial state

// Create the app machine
const appMachine = createMachine({
  id: 'app',
  slices: {
    ui: uiSlice,
    projects: projectsSlice,
    processes: processesSlice,
    features: featuresSlice,
  },
  context: {
    userID: null,
  },
});

export { appMachine };
```

### React Integration

```typescript
// Using useMachine hook - returns { state, actions }
function TabBar() {
  const { state, actions } = appMachine.useMachine('ui');

  return (
    <div>
      {state.projectOrder.map((id) => (
        <Tab
          key={id}
          active={id === state.activeTab}
          onClick={() => actions.setActiveTab(id)}
          onClose={() => actions.removeProject(id)}
        />
      ))}
    </div>
  );
}

// Using useSelector for derived state
function ProjectCount() {
  const count = appMachine.useSelector((state) => state.ui.projectOrder.length);
  return <span>{count} projects</span>;
}

// Accessing multiple slices
function ProcessPanel() {
  const { state: processes, actions } = appMachine.useMachine('processes');
  const { state: ui } = appMachine.useMachine('ui');

  const activeProcesses = Object.values(processes).filter(
    (p) => p.projectId === ui.activeTab
  );

  return (
    <div>
      {activeProcesses.map((process) => (
        <ProcessCard
          key={process.id}
          process={process}
          onKill={() => actions.kill(process.id)}
        />
      ))}
    </div>
  );
}

// Using async slice - handles loading/error states
function FeatureBoard({ projectPath }: { projectPath: string }) {
  const { state, actions } = appMachine.useMachine('features');

  // Trigger load on mount or path change
  React.useEffect(() => {
    actions.load(projectPath);
  }, [projectPath]);

  if (state.loading) {
    return <Spinner />;
  }

  if (state.failed) {
    return (
      <Alert variant="danger">
        {state.error}
        <Button onClick={() => actions.load(projectPath)}>Retry</Button>
      </Alert>
    );
  }

  if (!state.loaded || !state.value) {
    return <EmptyState>No features loaded</EmptyState>;
  }

  return (
    <KanbanBoard>
      {state.value.map((feature) => (
        <FeatureCard key={feature.id} feature={feature} />
      ))}
    </KanbanBoard>
  );
}
```

### Cache Policies

| Policy    | Behavior                                      |
|-----------|-----------------------------------------------|
| `public`  | Shared across all users, persisted            |
| `private` | Per-user, persisted (invalidates on userID change) |
| `session` | Per-session, cleared on app restart           |

