   useEffect(() => {
     const unlisten = listen('pty-output', (event) => {
       setLogs(prev => [...prev, {
         timestamp: Date.now(),
         processId: event.payload.process_id,
         message: event.payload.data,
         level: 'info'
       }]);
     });
     return () => { unlisten.then(fn => fn()); };
   }, []);
