            title="Welcome to HQ - Harness Orchestrator"
            actionClose={<AlertActionCloseButton onClose={() => setShowWelcome(false)} />}
          >
            <Content component="p">
              Manage your AI agent development sessions with visual task boards and real-time logs.
            </Content>
          </Alert>
        </PageSection>
      )}

      {/* Empty State when no projects */}
      {projects.length === 0 && (
        <PageSection>
          <EmptyState
            titleText="No Projects Open"
            headingLevel="h2"
            icon={FolderIcon}
          >
            <EmptyStateBody>
              Open a Harness project to start managing your AI agent development sessions.
