import { useState, useEffect, useCallback } from 'react';
import {
  Modal,
  ModalHeader,
  ModalBody,
  ModalFooter,
  Button,
  Form,
  FormGroup,
  TextInput,
  TextArea,
  FormSelect,
  FormSelectOption,
  Alert,
  Spinner,
} from '@patternfly/react-core';
import type { Feature } from '../state/store';

export type TaskData = {
  title: string;
  description: string;
  status: string;
  category: string;
};

export type TaskModalProps = {
  isOpen: boolean;
  onClose: () => void;
  onSave: (task: TaskData, taskId?: string) => Promise<void>;
  task?: Feature; // If provided, edit mode
};

const STATUS_OPTIONS = [
  { value: 'backlog', label: 'Backlog' },
  { value: 'todo', label: 'Todo' },
  { value: 'doing', label: 'Doing' },
  { value: 'review', label: 'Review' },
  { value: 'qa', label: 'QA' },
  { value: 'done', label: 'Done' },
];

export function TaskModal({
  isOpen,
  onClose,
  onSave,
  task,
}: TaskModalProps) {
  const [title, setTitle] = useState('');
  const [description, setDescription] = useState('');
  const [status, setStatus] = useState('todo');
  const [category, setCategory] = useState('');
  const [isSaving, setIsSaving] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const isEditMode = !!task;

  // Reset form when task changes or modal opens
  useEffect(() => {
    if (isOpen) {
      if (task) {
        setTitle(task.description || '');
        setDescription(task.steps?.[0] || '');
        setStatus(task.status?.toLowerCase() || 'todo');
        setPriority(task.priority?.toLowerCase() || 'medium');
        setCategory(task.category || '');
      } else {
        setTitle('');
        setDescription('');
        setStatus('todo');
        setPriority('medium');
        setCategory('');
      }
      setError(null);
    }
  }, [isOpen, task]);

  const handleSave = useCallback(async () => {
    if (!title.trim()) {
      setError('Title is required');
      return;
    }

    setIsSaving(true);
    setError(null);

    try {
      await onSave(
        {
          title: title.trim(),
          description: description.trim(),
          status,
          priority,
          category: category.trim(),
        },
        task?.id
      );
      onClose();
    } catch (e) {
      setError(e instanceof Error ? e.message : 'Failed to save task');
    } finally {
      setIsSaving(false);
    }
  }, [title, description, status, priority, category, task?.id, onSave, onClose]);

  return (
    <Modal
      isOpen={isOpen}
      onClose={onClose}
      aria-label={isEditMode ? 'Edit Task' : 'Add Task'}
      variant="medium"
    >
      <ModalHeader title={isEditMode ? 'Edit Task' : 'Add New Task'} />
      <ModalBody>
        {error && (
          <Alert variant="danger" title="Error" isInline style={{ marginBottom: 16 }}>
            {error}
          </Alert>
        )}
        <Form>
          <FormGroup label="Title" isRequired fieldId="task-title">
            <TextInput
              id="task-title"
              value={title}
              onChange={(_, value) => setTitle(value)}
              placeholder="Enter task title"
              isDisabled={isSaving}
            />
          </FormGroup>

          <FormGroup label="Description" fieldId="task-description">
            <TextArea
              id="task-description"
              value={description}
              onChange={(_, value) => setDescription(value)}
              placeholder="Enter task description (optional)"
              isDisabled={isSaving}
              rows={3}
            />
          </FormGroup>

          <FormGroup label="Status" fieldId="task-status">
            <FormSelect
              id="task-status"
              value={status}
              onChange={(_, value) => setStatus(value)}
              isDisabled={isSaving}
            >
              {STATUS_OPTIONS.map((opt) => (
                <FormSelectOption key={opt.value} value={opt.value} label={opt.label} />
              ))}
            </FormSelect>
          </FormGroup>

          <FormGroup label="Priority" fieldId="task-priority">
            <FormSelect
              id="task-priority"
              value={priority}
              onChange={(_, value) => setPriority(value)}
              isDisabled={isSaving}
            >
              {PRIORITY_OPTIONS.map((opt) => (
                <FormSelectOption key={opt.value} value={opt.value} label={opt.label} />
              ))}
            </FormSelect>
          </FormGroup>

          <FormGroup label="Category" fieldId="task-category">
            <TextInput
              id="task-category"
              value={category}
              onChange={(_, value) => setCategory(value)}
              placeholder="e.g., core, ui, docs (optional)"
              isDisabled={isSaving}
            />
          </FormGroup>
        </Form>
      </ModalBody>
      <ModalFooter>
        <Button
          variant="primary"
          onClick={handleSave}
          isDisabled={isSaving || !title.trim()}
          isLoading={isSaving}
        >
          {isSaving ? <Spinner size="sm" /> : isEditMode ? 'Save Changes' : 'Add Task'}
        </Button>
        <Button variant="link" onClick={onClose} isDisabled={isSaving}>
          Cancel
        </Button>
      </ModalFooter>
    </Modal>
  );
}

export default TaskModal;

