import { useState, useCallback } from 'react';
import {
  Card,
  CardBody,
  CardTitle,
  CardExpandableContent,
  CardHeader,
  Label,
  Flex,
  FlexItem,
  List,
  ListItem,
  Icon,
  Button,
  Tooltip,
} from '@patternfly/react-core';
import {
  CheckCircleIcon,
  OutlinedCircleIcon,
  PencilAltIcon,
  TrashIcon,
} from '@patternfly/react-icons';
import type { Feature } from '../state/store';

export type KanbanCardProps = {
  feature: Feature;
  onEdit?: () => void;
  onDelete?: () => void;
  onDragStart?: (e: React.DragEvent) => void;
  draggable?: boolean;
};

const priorityColors: Record<string, 'red' | 'orange' | 'blue' | 'grey'> = {
  critical: 'red',
  high: 'orange',
  medium: 'blue',
  low: 'grey',
};

const categoryColors: Record<string, 'purple' | 'teal' | 'green' | 'grey'> = {
  core: 'purple',
  ui: 'teal',
  setup: 'green',
};

export function KanbanCard({
  feature,
  onEdit,
  onDelete,
  onDragStart,
  draggable = false,
}: KanbanCardProps) {
  const [isExpanded, setIsExpanded] = useState(false);

  const handleExpand = useCallback(() => {
    setIsExpanded((prev) => !prev);
  }, []);

  const priorityColor = priorityColors[feature.priority] || 'grey';
  const categoryColor = categoryColors[feature.category] || 'grey';

  return (
    <Card
      id={`kanban-card-${feature.id}`}
      isExpanded={isExpanded}
      isCompact
      style={{
        marginBottom: '8px',
        cursor: draggable ? 'grab' : 'default',
      }}
      draggable={draggable}
      onDragStart={onDragStart}
    >
      <CardHeader
        onExpand={handleExpand}
        isToggleRightAligned
        toggleButtonProps={{
          id: `toggle-${feature.id}`,
          'aria-label': isExpanded ? 'Collapse' : 'Expand',
        }}
        actions={{
          actions: (
            <>
              {onEdit && (
                <Tooltip content="Edit task">
                  <Button
                    variant="plain"
                    aria-label="Edit task"
                    onClick={(e) => {
                      e.stopPropagation();
                      onEdit();
                    }}
                  >
                    <PencilAltIcon />
                  </Button>
                </Tooltip>
              )}
              {onDelete && (
                <Tooltip content="Delete task">
                  <Button
                    variant="plain"
                    aria-label="Delete task"
                    onClick={(e) => {
                      e.stopPropagation();
                      onDelete();
                    }}
                  >
                    <TrashIcon />
                  </Button>
                </Tooltip>
              )}
            </>
          ),
        }}
      >
        <CardTitle>
          <Flex
            direction={{ default: 'column' }}
            spaceItems={{ default: 'spaceItemsSm' }}
          >
            <FlexItem>
              <Flex spaceItems={{ default: 'spaceItemsSm' }}>
                <FlexItem>
                  <Label color={feature.passes ? 'green' : 'yellow'} isCompact>
                    {feature.id}
                  </Label>
                </FlexItem>
                <FlexItem>
                  <Label color={priorityColor} isCompact>
                    {feature.priority}
                  </Label>
                </FlexItem>
                <FlexItem>
                  <Label color={categoryColor} isCompact>
                    {feature.category}
                  </Label>
                </FlexItem>
              </Flex>
            </FlexItem>
            <FlexItem>
              <span style={{ fontSize: '0.9rem', fontWeight: 500 }}>
                {feature.description.split(' - ')[0]}
              </span>
            </FlexItem>
          </Flex>
        </CardTitle>
      </CardHeader>
      <CardExpandableContent>
        <CardBody>
          <p style={{ marginBottom: '12px', color: '#6a6e73' }}>
            {feature.description}
          </p>
          <strong>Steps:</strong>
          <List isPlain style={{ marginTop: '8px' }}>
            {feature.steps.map((step, idx) => (
              <ListItem key={idx} icon={<StepIcon passes={feature.passes} />}>
                {step}
              </ListItem>
            ))}
          </List>
        </CardBody>
      </CardExpandableContent>
    </Card>
  );
}

function StepIcon({ passes }: { passes: boolean }) {
  if (passes) {
    return (
      <Icon status="success">
        <CheckCircleIcon />
      </Icon>
    );
  }
  return (
    <Icon status="warning">
      <OutlinedCircleIcon />
    </Icon>
  );
}

export default KanbanCard;

